def are_near_duplicates(memory1, memory2):
    # Calculate Jaccard similarity coefficient
    def jaccard_similarity(set1, set2):
        intersection = set1 & set2
        union = set1 | set2
        return len(intersection) / len(union)

    # Convert memories to sets of key-value pairs
    memory1_set = {(k, v) for k, v in memory1.items()}
    memory2_set = {(k, v) for k, v in memory2.items()}

    # Calculate Jaccard similarity coefficient
    sim = jaccard_similarity(memory1_set, memory2_set)

    return sim >= 0.5  # Define your own threshold here
